PRAGMA foreign_keys=ON;
CREATE TABLE scanners(id INTEGER PRIMARY KEY AUTOINCREMENT,codigo TEXT UNIQUE,codigo_qr TEXT UNIQUE,marca TEXT,modelo TEXT,estado TEXT,numero_serie TEXT UNIQUE,imei TEXT UNIQUE,iccid TEXT UNIQUE,area_id INTEGER,activo INTEGER DEFAULT 1,created_by INTEGER,updated_by INTEGER,deactivated_at TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE scanner_movimientos(id INTEGER PRIMARY KEY AUTOINCREMENT,scanner_id INTEGER,folio TEXT UNIQUE,estado TEXT,persona_entrega_nombre TEXT,numero_empleado TEXT,area_id INTEGER,turno TEXT,entregado_at TEXT,recibido_at TEXT,vence_at TEXT,entrega_registrada_por INTEGER,recepcion_registrada_por INTEGER,devolucion_recibida_por_nombre TEXT,duracion_segundos INTEGER,observaciones TEXT,cancelado_por INTEGER,cancelado_at TEXT,motivo_cancelacion TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE UNIQUE INDEX one_open ON scanner_movimientos(scanner_id) WHERE estado='abierto';
CREATE TABLE scanner_inspecciones(id INTEGER PRIMARY KEY AUTOINCREMENT,movimiento_id INTEGER,scanner_id INTEGER,tipo TEXT,bateria_porcentaje INTEGER,calificacion INTEGER,observaciones TEXT,firma_usuario_evidencia_id INTEGER,firma_responsable_evidencia_id INTEGER,inspeccionada_at TEXT,registrada_por INTEGER,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP,UNIQUE(movimiento_id,tipo));
CREATE TABLE scanner_inspeccion_detalles(id INTEGER PRIMARY KEY AUTOINCREMENT,inspeccion_id INTEGER,componente TEXT,estado TEXT,valor_numerico REAL,valor_texto TEXT,observaciones TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,UNIQUE(inspeccion_id,componente));
CREATE TABLE scanner_incidencias(id INTEGER PRIMARY KEY AUTOINCREMENT,scanner_id INTEGER,movimiento_id INTEGER,tipo TEXT,severidad TEXT,descripcion TEXT,estado TEXT,reportado_por_nombre TEXT,registrada_por INTEGER,reportada_at TEXT,resolucion TEXT,resuelta_por INTEGER,resuelta_at TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE scanner_evidencias(id INTEGER PRIMARY KEY AUTOINCREMENT,scanner_id INTEGER,movimiento_id INTEGER,inspeccion_id INTEGER,incidencia_id INTEGER,tipo TEXT,ruta_storage TEXT,mime_type TEXT,tamano_bytes INTEGER,hash_sha256 TEXT,capturada_at TEXT,registrada_por INTEGER,activo INTEGER,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE auditoria_eventos(id INTEGER PRIMARY KEY AUTOINCREMENT,usuario_id INTEGER,accion TEXT,modulo TEXT,entidad TEXT,entidad_id INTEGER,resultado TEXT,valor_anterior_json TEXT,valor_nuevo_json TEXT,metadata_json TEXT,ip TEXT,request_id TEXT,session_fingerprint TEXT,created_at TEXT);
